type CommentView struct {
	Author        string
	SafeContent   template.HTML
	FormattedTime string
}

type PageData struct {
	Comments []CommentView
	Count    int
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl, err := template.New("page").Parse(pageTemplate)
	if err != nil {
		http.Error(w, "Error parsing template", http.StatusInternalServerError)
		log.Printf("Template parse error: %v", err)
		return
	}

	var commentViews []CommentView
	for _, c := range comments {
		cv := CommentView{
			Author:        c.Author,
			SafeContent:   sanitizeHTML(c.Content),
			FormattedTime: c.CreatedAt.Format("Jan 2, 2006 at 3:04 PM"),
		}
		commentViews = append(commentViews, cv)
	}

	data := PageData{
		Comments: commentViews,
		Count:    len(commentViews),
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	err = tmpl.Execute(w, data)
	if err != nil {
		log.Printf("Template execution error: %v", err)
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)

	addr := ":8080"
	log.Printf("Starting server on %s", addr)
	log.Printf("Visit http://localhost%s to view comments", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}